use std::{
    collections::{BTreeMap, HashMap},
    time::Duration,
};

use rand::Rng;
use serde::{de::DeserializeOwned, Deserialize, Deserializer, Serialize, Serializer};
use serde_json::value::RawValue;
use sqlx::types::Json;
use sqlx::types::JsonRawValue;

use crate::{
    assets::AssetWithAltAccessType,
    more_serde::{default_empty_string, default_id, default_null, default_true, is_default},
    runnable_settings::{ConcurrencySettings, ConcurrencySettingsWithCustom, DebouncingSettings},
    scripts::{Schema, ScriptHash, ScriptLang},
    to_raw_value,
};

#[derive(Debug, Serialize, Deserialize, sqlx::FromRow)]
pub struct Flow {
    pub workspace_id: String,
    pub path: String,
    pub summary: String,
    pub description: String,
    pub value: Json>, pub edited_by: String, pub edited_at: chrono::DateTime, pub archived: bool, pub schema: Option, pub extra_perms: serde_json::Value, #[serde(skip_serializing_if = "Option::is_none")] pub draft_only: Option, #[serde(skip_serializing_if = "Option::is_none")] pub dedicated_worker: Option, #[serde(skip_serializing_if = "Option::is_none")] pub tag: Option, #[serde(skip_serializing_if = "is_none_or_false")] pub ws_error_handler_muted: Option, #[serde(skip_serializing_if = "Option::is_none")] pub timeout: Option, #[serde(skip_serializing_if = "is_none_or_false")] pub visible_to_runner_only: Option, #[serde(skip_serializing_if = "Option::is_none")] pub on_behalf_of_email: Option, #[serde(skip_serializing_if = "Option::is_none")] pub labels: Option>, /// Labels inherited from the parent folder, computed at read time. Not stored on the flow row. #[sqlx(default)] #[serde(default, skip_serializing_if = "Option::is_none")] pub inherited_labels: Option>, } #[derive(Serialize, sqlx::FromRow)] pub struct FlowWithStarred { #[sqlx(flatten)] #[serde(flatten)] pub flow: Flow, #[serde(skip_serializing_if = "Option::is_none")] pub starred: Option, #[serde(skip_serializing_if = "Option::is_none")] pub lock_error_logs: Option, pub version_id: i64, } pub fn is_none_or_false(b: &Option) -> bool { b.is_none() || !b.unwrap() } fn is_false(b: &bool) -> bool { !*b } #[derive(Serialize, sqlx::FromRow)] pub struct ListableFlow { pub workspace_id: String, pub path: String, pub summary: String, #[serde(skip_serializing_if = "Option::is_none")] pub description: Option, pub edited_by: Option, pub edited_at: Option>, pub archived: bool, pub extra_perms: serde_json::Value, pub starred: bool, pub has_draft: bool, #[serde(skip_serializing_if = "Option::is_none")] pub draft_only: Option, #[serde(skip_serializing_if = "Option::is_none")] pub ws_error_handler_muted: Option, #[sqlx(default)] #[serde(skip_serializing_if = "Option::is_none")] pub deployment_msg: Option, #[serde(skip_serializing_if = "Option::is_none")] pub labels: Option>, /// Labels inherited from the parent folder, computed at read time. #[sqlx(default)] #[serde(skip_serializing_if = "Option::is_none")] pub inherited_labels: Option>, } #[derive(Debug, Serialize, Deserialize, sqlx::FromRow)] pub struct NewFlow { pub path: String, pub summary: String, pub description: Option, #[serde(deserialize_with = "validate_flow_value")] pub value: Box, pub schema: Option, pub draft_only: Option, pub tag: Option, pub dedicated_worker: Option, pub timeout: Option, pub deployment_message: Option, pub visible_to_runner_only: Option, pub on_behalf_of_email: Option, pub preserve_on_behalf_of: Option, pub ws_error_handler_muted: Option, #[serde(default)] pub labels: Option>, /// Caller-intent flag (set by the CLI / git sync): when true, deploying /// this flow must NOT delete an existing user draft at the same path. /// Transient — never persisted. #[serde(default, skip_serializing_if = "Option::is_none")] pub skip_draft_deletion: Option, } impl NewFlow { pub fn parse_flow_value(&self) -> anyhow::Result { serde_json::from_str(self.value.get()) .map_err(|e| anyhow::anyhow!("Failed to parse flow value: {}", e)) } } fn validate_retry(retry: &Retry, module_id: &str) -> anyhow::Result<()> { if retry.exponential.attempts > 0 && retry.exponential.seconds == 0 { return Err(anyhow::anyhow!( "Module '{}': Exponential backoff base (seconds) must be greater than 0. A base of 0 would cause immediate retries.", module_id )); } Ok(()) } fn validate_flow_value<'de, D>(deserializer: D) -> Result, D::Error> where D: Deserializer<'de>, { let raw_value = Box::::deserialize(deserializer)?; let flow_value: FlowValue = serde_json::from_str(raw_value.get()) .map_err(|e| serde::de::Error::custom(format!("Invalid flow value: {}", e)))?; FlowModule::traverse_modules(&flow_value.modules, &mut |module| { if let Some(ref retry) = module.retry { validate_retry(retry, &module.id)?; } return Ok(()); }) .map_err(|e| serde::de::Error::custom(e.to_string()))?; if let Some(ref _failure_module) = flow_value.failure_module { //add validation logic here for failure module } if let Some(ref _preprocessor_module) = flow_value.preprocessor_module { //add validation logic here for preprocessor module } Ok(raw_value) } #[derive(Deserialize, Serialize, Debug, Clone, Default)] pub struct FlowValue { pub modules: Vec, #[serde(skip_serializing_if = "Option::is_none")] #[serde(default)] pub failure_module: Option>, #[serde(skip_serializing_if = "Option::is_none")] #[serde(default)] pub preprocessor_module: Option>, #[serde(default)] #[serde(skip_serializing_if = "is_default")] pub same_worker: bool, // When the flow runs on a custom worker tag, by default that tag is propagated to // (and overrides) every step, script and nested sub-flow. Set this to true to instead // let steps that declare their own non-empty tag run on it; steps without their own tag // still inherit the flow's tag. Defaults to false to preserve the historical behavior. #[serde(default)] #[serde(skip_serializing_if = "is_default")] pub preserve_step_tags: bool, #[serde(flatten)] pub concurrency_settings: ConcurrencySettings, #[serde(flatten)] pub debouncing_settings: DebouncingSettings, #[serde(skip_serializing_if = "Option::is_none")] pub skip_expr: Option, #[serde(skip_serializing_if = "Option::is_none")] pub cache_ttl: Option, #[serde(skip_serializing_if = "Option::is_none")] pub cache_ignore_s3_path: Option, #[serde(skip_serializing_if = "Option::is_none")] pub early_return: Option, #[serde(skip_serializing_if = "Option::is_none")] // Priority at the flow level pub priority: Option, #[serde(skip_serializing_if = "Option::is_none")] pub chat_input_enabled: Option, #[serde(skip_serializing_if = "Option::is_none")] pub flow_env: Option>>, #[serde(skip_serializing, default)] pub delete_after_use: Option, #[serde(skip_serializing_if = "Option::is_none")] pub delete_after_secs: Option, } impl FlowValue { pub fn get_flow_module_at_step(&self, step: Step) -> anyhow::Result<&FlowModule> { use anyhow::Context; let flow_module = match step { Step::PreprocessorStep => self .preprocessor_module .as_deref() .with_context(|| format!("no preprocessor module")), Step::Step { idx, .. } => self .modules .get(idx) .with_context(|| format!("no module found at index: {idx}")), Step::FailureStep => self .failure_module .as_deref() .with_context(|| format!("no failure module")), }; flow_module } pub fn traverse_leafs anyhow::Result<()>>( modules: Vec<&FlowModule>, cb: &mut C, ) -> anyhow::Result<()> { use FlowModuleValue::*; for module in modules { match serde_json::from_str::(module.value.get())? { s @ (Script { .. } | RawScript { .. } | Flow { .. } | FlowScript { .. } | Identity) => cb(&s, &module.id)?, ForloopFlow { modules, .. } | WhileloopFlow { modules, .. } => { Self::traverse_leafs(modules.iter().collect(), cb)? } AIAgent { tools, .. } => { for tool in tools { match &tool.value { ToolValue::FlowModule(module_value) => cb(module_value, &tool.id)?, ToolValue::Mcp(_) => {} ToolValue::Websearch(_) => {} } } } BranchOne { default, branches, .. } => { Self::traverse_leafs(default.iter().collect(), cb)?; for branch in branches { Self::traverse_leafs(branch.modules.iter().collect(), cb)?; } } BranchAll { branches, .. } => { for branch in branches { Self::traverse_leafs(branch.modules.iter().collect(), cb)?; } } } } Ok(()) } } #[derive(Debug, Copy, Clone)] pub enum Step { Step { idx: usize, len: usize }, PreprocessorStep, FailureStep, } impl Step { pub fn from_i32_and_len(step: i32, len: usize) -> Self { if step < 0 { Step::PreprocessorStep } else if (step as usize) < len { Step::Step { idx: step as usize, len } } else { Step::FailureStep } } pub fn get_step_index(&self) -> Option { match self { Step::Step { idx, .. } => Some(*idx), _ => None, } } pub fn is_index_step(&self) -> bool { matches!(self, Step::Step { .. }) } pub fn is_preprocessor_step(&self) -> bool { matches!(self, Step::PreprocessorStep) } pub fn is_failure_s